/** Compact user chip with a relative "joined" date. */

import { formatRelative } from '../utils/dates';
import type { User } from '../types';

export interface UserBadgeProps {
  user: User;
  joinedAt: string;
}

export function UserBadge({ user, joinedAt }: UserBadgeProps) {
  return (
    <span className="user-badge" title={user.email}>
      {user.name} · joined {formatRelative(joinedAt)}
    </span>
  );
}

"""Time helpers."""

from datetime import datetime, timezone


def utc_now_iso() -> str:
    """Current UTC time as an ISO-8601 string."""
    return datetime.now(timezone.utc).isoformat()


def parse_iso(value: str) -> datetime:
    """Parse an ISO-8601 string into an aware datetime."""
    dt = datetime.fromisoformat(value)
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)
    return dt


def humanize_delta(seconds: float) -> str:
    """Render a duration in seconds as a short human string like '3h' or '2d'."""
    if seconds < 60:
        return f"{int(seconds)}s"
    if seconds < 3600:
        return f"{int(seconds // 60)}m"
    if seconds < 86400:
        return f"{int(seconds // 3600)}h"
    return f"{int(seconds // 86400)}d"

"""Task routes."""

from pyserver.db import Database
from pyserver.models.task import TaskStatus, task_from_row
from pyserver.utils.time import utc_now_iso
from pyserver.validators import validate_title


def list_tasks(db: Database, params: dict) -> list[dict]:
    """Return all tasks, optionally filtered by status."""
    status = params.get("status")
    if status:
        rows = db.fetch_all("SELECT * FROM tasks WHERE status = ?", (status,))
    else:
        rows = db.fetch_all("SELECT * FROM tasks")
    return [task_from_row(row).__dict__ for row in rows]


def create_task(db: Database, payload: dict) -> dict:
    """Create a new task from a JSON payload."""
    title = validate_title(payload["title"])
    cursor = db.execute(
        "INSERT INTO tasks (title, status, owner_id, created_at) VALUES (?, ?, ?, ?)",
        (title, TaskStatus.OPEN.value, payload.get("owner_id"), utc_now_iso()),
    )
    return {"id": cursor.lastrowid, "title": title}


def complete_task(db: Database, payload: dict) -> dict:
    """Mark a task as done."""
    task_id = payload["task_id"]
    db.execute(
        "UPDATE tasks SET status = ? WHERE id = ?",
        (TaskStatus.DONE.value, task_id),
    )
    return {"id": task_id, "status": TaskStatus.DONE.value}
